        Set<Integer> visited = new HashSet<>();
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(start);
        visited.add(start);
        while (!queue.isEmpty()) {
            int idx = queue.poll();
            if (arr[idx] == 0) return true;
            for (int next : new int[]{idx + arr[idx], idx - arr[idx]}) {
                if (next >= 0 && next < n && !visited.contains(next)) {
                    visited.add(next);
                    queue.offer(next);
                }
            }
        }
        return false;
    }
